import{PDFViewer}from"./viewers/pdf-viewer.min.js";import{ImageViewer}from"./viewers/image-viewer.min.js";import{CSVViewer}from"./viewers/csv-viewer.min.js";import{InvalidInputError}from"./errors.min.js";export class FileViewerFactory{static createViewer(e){switch(e.toLowerCase()){case".pdf":return new PDFViewer;case".png":case".svg":case".jpeg":case".jpg":return new ImageViewer;case".csv":return new CSVViewer;default:throw new InvalidInputError(`Unsupported file type: ${e}`)}}}